use strict;
use warnings;

sub factorial_recursive {
    my ($n) = @_;
    return 1 if $n <= 1;
    return $n * factorial_recursive($n - 1);
}

sub factorial_iterative {
    my ($n) = @_;
    my $result = 1;
    $result *= $_ for 2 .. $n;
    return $result;
}

print "Faktoriyel tablosu (0-10):\n";
for my $i (0 .. 10) {
    print "$i! = " . factorial_iterative($i) . "\n";
}

print "\nRecursive 5! = " . factorial_recursive(5) . "\n";
print "Iteratif 5! = " . factorial_iterative(5) . "\n";

# Kombinasyon hesaplama: C(n,r) = n! / (r! * (n-r)!)
my ($n, $r) = (5, 2);
my $combination = factorial_iterative($n) / (factorial_iterative($r) * factorial_iterative($n - $r));
print "\nC($n,$r) = $combination\n";
